COPY (SELECT hs.session_id, hs.status, hs.requested_volume_gbps, hs.accepted_volume_gbps, hs.response_time_ms, p.max_scrubbing_capacity_gbps, p.measured_latency_ms, COALESCE(ts.overall_score, 0.5) as trust_score, COALESCE(rl.balance, 0) as reciprocity_balance, a.peak_volume_gbps, a.severity, a.attack_type FROM "HELP_SESSIONS" hs JOIN "PEERS" p ON hs.helping_peer_id = p.peer_id LEFT JOIN "TRUST_SCORES" ts ON p.peer_id = ts.peer_id LEFT JOIN "RECIPROCITY_LEDGER" rl ON p.peer_id = rl.peer_id JOIN "ATTACKS" a ON hs.attack_id = a.attack_id) TO '/tmp/sessions.csv' CSV HEADER;
